// assetDeleteConfirm builds the delete confirm string with real impact
// counts. The UsedBy list is already populated by the handler, so we
// can tell users exactly how many entities will lose their sprite.
func assetDeleteConfirm(usedBy []RailRef) string {
	if len(usedBy) == 0 {
		return "Delete this asset? Variants and animation tags go with it."
	}
	if len(usedBy) == 1 {
		return "Delete this asset? 1 entity will lose its sprite. Variants and animation tags go with it."
	}
	return fmt.Sprintf("Delete this asset? %d entities will lose their sprite. Variants and animation tags go with it.", len(usedBy))
}

