// decodeTileSheetMD reads the tile-sheet metadata back off the asset row.
// Bool return is false when the metadata column is empty / non-tile-shaped
// so the template can fall back to a plain image preview.
func decodeTileSheetMD(a assets.Asset) (assets.TileSheetMetadata, bool) {
	md, err := assets.DecodeTileSheetMetadata(a.MetadataJSON)
	if err != nil || md.Cols == 0 || md.TileSize == 0 {
		return assets.TileSheetMetadata{}, false
	}
	return md, true
}

func tilePreviewCanvasW(md assets.TileSheetMetadata, maxCols int) int {
	cols := md.Cols
	if maxCols > 0 && cols > maxCols {
		cols = maxCols
	}
	return cols * 32
}

func tilePreviewCanvasH(md assets.TileSheetMetadata, maxRows int) int {
	rows := md.Rows
	if maxRows > 0 && rows > maxRows {
		rows = maxRows
	}
	return rows * 32
}

func tilePreviewNonEmpty(md assets.TileSheetMetadata) string {
	parts := make([]string, 0, len(md.NonEmptyIndex))
	for _, idx := range md.NonEmptyIndex {
		parts = append(parts, fmt.Sprintf("%d", idx))
	}
	return strings.Join(parts, ",")
}

// AudioPreview renders the waveform + native playback controls. The
// waveform decodes via Web Audio in waveform.ts; playback uses
